2291:           peerlen = ASN1_STRING_length(tmp);
2292:           if(peerlen >= 0) {
2293:             peer_CN = OPENSSL_malloc(peerlen + 1);
2294:             if(peer_CN) {
2295:               memcpy(peer_CN, ASN1_STRING_get0_data(tmp), peerlen);
